/**
 * Regression test: CLI argument validation.
 *
 * Runs smolctl with malformed flags and asserts the error messages
 * are clear. Does not require a running smolvm server.
 */

const CLI = new URL("../cli/smolctl.ts", import.meta.url).pathname;

async function runCli(args: string[]): Promise<{ code: number; stderr: string }> {
  const cmd = new Deno.Command("deno", {
    args: ["run", "--allow-net", "--allow-env", "--allow-read", "--allow-run", "--allow-write", CLI, ...args],
    stdout: "null",
    stderr: "piped",
  });
  const { code, stderr } = await cmd.output();
  return { code, stderr: new TextDecoder().decode(stderr) };
}

let failed = 0;
function check(name: string, ok: boolean, detail = "") {
  if (ok) {
    console.log(`  ✓ ${name}`);
  } else {
    console.log(`  ✗ ${name}${detail ? `: ${detail}` : ""}`);
    failed++;
  }
}

console.log("\nCLI argument validation:");

// Flag at end of args with no value should error clearly.
{
  const { code, stderr } = await runCli(["create", "foo", "--cpus"]);
  check("missing value: exits non-zero", code !== 0, `code=${code}`);
  check(
    "missing value: error names the flag",
    stderr.includes("--cpus") && /requires a value/.test(stderr),
    stderr.split("\n")[0],
  );
}

// A flag consuming the next flag as its value is a common CLI footgun; should error.
{
  const { code, stderr } = await runCli(["create", "foo", "--cpus", "--memory", "512"]);
  check("flag-as-value: exits non-zero", code !== 0, `code=${code}`);
  check(
    "flag-as-value: error names the flag",
    stderr.includes("--cpus") && /requires a value/.test(stderr),
    stderr.split("\n")[0],
  );
}

console.log(failed === 0 ? "\nAll passed.\n" : `\n${failed} failed.\n`);
Deno.exit(failed === 0 ? 0 : 1);

