/**
 * Regression test — createFleet() input validation.
 *
 * Runs without a server. Exercises validation-only code paths that
 * throw before any HTTP call, so no SmolvmHttpClient connection is made.
 */

import { SmolvmHttpClient, createFleet } from "../sdk-ts/mod.ts";
import { MachineFleet } from "../sdk-ts/fleet.ts";

// createFleet lives on the fleet.ts module; import it directly to avoid
// depending on SmolvmClient side-effects.
import { createFleet as _createFleet } from "../sdk-ts/fleet.ts";

const http = new SmolvmHttpClient("http://127.0.0.1:1"); // never contacted
let failures = 0;

async function expectThrows(
  label: string,
  fn: () => Promise<unknown>,
  needle: string,
): Promise<void> {
  try {
    await fn();
    console.log(`  ❌ ${label}: expected throw, got success`);
    failures++;
  } catch (e) {
    const msg = e instanceof Error ? e.message : String(e);
    if (msg.includes(needle)) {
      console.log(`  ✓ ${label}`);
    } else {
      console.log(`  ❌ ${label}: wrong message — ${msg}`);
      failures++;
    }
  }
}

console.log("createFleet input validation:");
await expectThrows(
  "count = 0 rejected",
  () => _createFleet(http, "x", 0),
  "positive integer",
);
await expectThrows(
  "count = -1 rejected",
  () => _createFleet(http, "x", -1),
  "positive integer",
);
await expectThrows(
  "count = 1.5 rejected",
  () => _createFleet(http, "x", 1.5),
  "positive integer",
);
await expectThrows(
  "count = NaN rejected",
  () => _createFleet(http, "x", NaN),
  "positive integer",
);
await expectThrows(
  "empty prefix rejected",
  () => _createFleet(http, "", 1),
  "non-empty string",
);

// Re-export sanity — ensures public surface still exposes these.
if (typeof createFleet !== "function") {
  console.log("  ❌ createFleet not exported from mod.ts");
  failures++;
}
if (typeof MachineFleet !== "function") {
  console.log("  ❌ MachineFleet class not importable");
  failures++;
}

if (failures > 0) {
  console.log(`\n${failures} failure(s)`);
  Deno.exit(1);
}
console.log("\nAll validation tests passed.");

